import functions_framework
import json
import hmac
import hashlib
import os
from flask import jsonify

WEBHOOK_SECRET = os.environ.get('WEBHOOK_SECRET', 'your-secret-key-here')

def verify_signature(payload, signature_header):
    """Verify the webhook signature"""
    if not signature_header:
        return False
    
    expected_signature = hmac.new(
        WEBHOOK_SECRET.encode('utf-8'),
        payload.encode('utf-8'),
        hashlib.sha256
    ).hexdigest()
    
    return hmac.compare_digest(expected_signature, signature_header)

@functions_framework.http
def webhook_handler(request):
    """HTTP Cloud Function to handle webhook events"""
    
    if request.method != 'POST':
        return jsonify({'error': 'Method not allowed'}), 405
    
    signature = request.headers.get('X-Webhook-Signature')
    
    try:
        payload = request.get_data(as_text=True)
        
        if not verify_signature(payload, signature):
            return jsonify({'error': 'Invalid signature'}), 401
        
        data = json.loads(payload)
        
        event_type = data.get('event_type')
        
        if event_type == 'payment.success':
            process_payment_success(data)
        elif event_type == 'payment.failed':
            process_payment_failed(data)
        elif event_type == 'payment.refund':
            process_payment_refund(data)
        else:
            return jsonify({'error': 'Unknown event type'}), 400
        
        return jsonify({'status': 'success', 'message': 'Webhook processed'}), 200
        
    except json.JSONDecodeError:
        return jsonify({'error': 'Invalid JSON'}), 400
    except Exception as e:
        print(f"Error processing webhook: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

def process_payment_success(data):
    """Process successful payment events"""
    payment_id = data.get('payment_id')
    amount = data.get('amount')
    customer_id = data.get('customer_id')
    
    print(f"Payment success: {payment_id}, Amount: {amount}, Customer: {customer_id}")

def process_payment_failed(data):
    """Process failed payment events"""
    payment_id = data.get('payment_id')
    reason = data.get('reason')
    customer_id = data.get('customer_id')
    
    print(f"Payment failed: {payment_id}, Reason: {reason}, Customer: {customer_id}")

def process_payment_refund(data):
    """Process refund events"""
    payment_id = data.get('payment_id')
    refund_amount = data.get('refund_amount')
    customer_id = data.get('customer_id')
    
    print(f"Payment refund: {payment_id}, Amount: {refund_amount}, Customer: {customer_id}")